def detect_cycle_directed_graph(graph):
    """
    Directed graph'ta döngü olup olmadığını tespit eder.

    Args:
        graph: Sözlük olarak temsil edilen yönlendirilmiş grafik.
               Anahtarlar düğümleri, değerler ise komşu düğümlerin listesidir.

    Returns:
        Grafikte döngü varsa True, aksi takdirde False.
    """
    num_nodes = len(graph)
    visited = [False] * num_nodes
    recursion_stack = [False] * num_nodes

    def dfs(node):
        visited[node] = True
        recursion_stack[node] = True

        for neighbor in graph.get(node, []):
            if not visited[neighbor]:
                if dfs(neighbor):
                    return True
            elif recursion_stack[neighbor]:
                return True

        recursion_stack[node] = False
        return False

    for node in graph:
        if not visited[node]:
            if dfs(node):
                return True

    return False

if __name__ == '__main__':
    # Örnek grafik 1: Döngü yok
    graph1 = {
